int escalonMasLargo(vector<int>& v, int inicio, int fin) {
    if (inicio == fin) {
        // Caso base: un solo elemento
        return 1;
    }
    int medio = (inicio + fin) / 2;
    int izq = escalonMasLargo(v, inicio, medio);
    int der = escalonMasLargo(v, medio + 1, fin);
    // Calcular el escalón que cruza el medio
    int cruzado = calcularCruzado(v, inicio, medio, fin);
    // Devolver el máximo de los tres
    return max(izq, max(der, cruzado));
}

